#!/usr/bin/env node

import { parseArgs } from 'node:util';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { buildRun } from '../parser/index.js';

const __dirname = dirname(fileURLToPath(import.meta.url));

const args = process.argv.slice(2);

// Handle --version
if (args.includes('--version')) {
  const pkg = JSON.parse(readFileSync(join(__dirname, '..', 'package.json'), 'utf8'));
  console.log(pkg.version);
  process.exit(0);
}

const command = args[0];

if (command === 'parse') {
  await runParse(args.slice(1));
} else if (command === 'merge') {
  await runMergeCli(args.slice(1));
} else if (command === 'init') {
  await runInitCli(args.slice(1));
} else {
  console.error(`Unknown command: ${command}`);
  console.error('Usage: e2e-dashboard <parse|merge|init> [options]');
  process.exit(1);
}

async function runParse(argv) {
  const { values } = parseArgs({
    args: argv,
    options: {
      'run-id': { type: 'string' },
      sha: { type: 'string' },
      message: { type: 'string' },
      branch: { type: 'string' },
      playwright: { type: 'string' },
      'maestro-android': { type: 'string' },
      'maestro-ios': { type: 'string' },
      'screenshots-dir': { type: 'string' },
      'output-dir': { type: 'string' },
    },
  });

  if (!values['run-id']) {
    console.error('Error: --run-id is required');
    process.exit(1);
  }

  try {
    const run = await buildRun({
      runId: values['run-id'],
      sha: values.sha || null,
      message: values.message ? values.message.slice(0, 120) : null,
      branch: values.branch || null,
      playwrightPath: values.playwright || null,
      maestroAndroidPath: values['maestro-android'] || null,
      maestroIosPath: values['maestro-ios'] || null,
      screenshotsDir: values['screenshots-dir'] || null,
      outputDir: values['output-dir'] || null,
    });

    console.log(JSON.stringify(run, null, 2));
  } catch (err) {
    console.warn(`Warning: Parse failed: ${err.message}`);
    console.log(JSON.stringify({
      id: values['run-id'],
      sha: values.sha || null,
      message: values.message || null,
      branch: values.branch || null,
      timestamp: new Date().toISOString(),
      suites: {},
    }, null, 2));
  }
}

async function runMergeCli(argv) {
  const { values } = parseArgs({
    args: argv,
    options: {
      history: { type: 'string' },
      new: { type: 'string' },
      output: { type: 'string' },
      'max-runs': { type: 'string' },
      'screenshots-base': { type: 'string' },
    },
  });

  if (!values.history || !values.new || !values.output) {
    console.error('Error: --history, --new, and --output are required');
    process.exit(1);
  }

  const { mergeHistory } = await import('../merger/index.js');
  mergeHistory({
    historyPath: values.history,
    newRunPath: values.new,
    outputPath: values.output,
    maxRuns: parseInt(values['max-runs'] || '50', 10),
    screenshotsBase: values['screenshots-base'] || null,
  });
}

async function runInitCli(argv) {
  const { values } = parseArgs({
    args: argv,
    options: {
      platform: { type: 'string' },
    },
  });

  if (!values.platform || !['github', 'forgejo'].includes(values.platform)) {
    console.error('Error: --platform must be "github" or "forgejo"');
    process.exit(1);
  }

  const { scaffold } = await import('../scaffold/index.js');
  scaffold({ platform: values.platform });
}
